from langchain.schema import BaseRetriever
from collections import Counter
import re

class BiasDetector:
    PROTECTED_CLASSES = {
        'gender': ['man', 'woman', 'male', 'female'],
        'race': ['black', 'white', 'asian', 'latino'],
        'age': ['young', 'old', 'elderly', 'youth']
    }

    def analyze_bias(self, docs: list[str]) -> dict:
        counters = {}
        for category, terms in self.PROTECTED_CLASSES.items():
            counter = Counter()
            for doc in docs:
                for term in terms:
                    counter[term] += len(re.findall(term, doc.lower()))
            counters[category] = dict(counter)
        return counters

# Usage in RAG chain
retriever = ...  # Your retriever
detector = BiasDetector()
docs = retriever.get_relevant_documents('successful entrepreneurs')
bias_scores = detector.analyze_bias([doc.page_content for doc in docs])
print(bias_scores)
