import { ChatOpenAI } from "langchain/chat_models/openai";
import { PromptTemplate } from "langchain/prompts";

import * as toxicity from '@tensorflow-models/toxicity';

class BiasAnalyzer {
  toxicityClassifier: any;

  async analyzeOutputDistribution(output: string): Promise<Record<string, number>> {
    this.toxicityClassifier = await toxicity.load();
    const predictions = await this.toxicityClassifier.classify([output]);
    return predictions.reduce((acc, pred) => {
      acc[pred.label] = pred.results[0].match;
      return acc;
    }, {} as Record<string, number>);
  }
}

const analyzer = new BiasAnalyzer();
const chain = PromptTemplate.fromTemplate("{input}") | new ChatOpenAI();
const result = await chain.invoke({ input: "CEO John Smith" });
const biasScores = await analyzer.analyzeOutputDistribution(result.content as string);
console.log(biasScores);
